#!/usr/bin/env node

import { existsSync } from 'node:fs';
import { spawnSync } from 'node:child_process';
import { dirname, resolve } from 'node:path';
import { fileURLToPath } from 'node:url';

const here = dirname(fileURLToPath(import.meta.url));
const sourcePath = resolve(here, '../src/native-host-bridge.ts');
const distPath = resolve(here, '../dist/native-host-bridge.js');
const forwardedArgv = process.argv.slice(2);

async function main() {
  if (existsSync(distPath)) {
    const moduleNamespace = await import(distPath);
    if (typeof moduleNamespace.main !== 'function') {
      throw new Error(
        `gnosis-host bundle at ${distPath} does not export main().`
      );
    }
    process.exitCode = await moduleNamespace.main(forwardedArgv);
    return;
  }

  const result = spawnSync(
    process.execPath,
    ['--import', 'tsx', sourcePath, ...forwardedArgv],
    {
      env: process.env,
      stdio: 'inherit',
    }
  );

  if (result.error) {
    throw result.error;
  }

  process.exitCode = result.status ?? 1;
}

main().catch((error) => {
  process.stderr.write(
    `${error instanceof Error ? error.stack ?? error.message : String(error)}\n`
  );
  process.exitCode = 1;
});
